CDF1.formula:
IF(
    OR(
        /* Already Resolved and late */
        AND(NOT(ISBLANK(CustomOpportunity__c.TAG_Resolved_Date_Time__c)), CustomOpportunity__c.TAG_Resolved_Date_Time__c > CustomOpportunity__c.TAG_DueDateTime__c),

        /* Still Open and late */
        AND(ISPICKVAL(CustomOpportunity__c.InclusionStage__c, "Ny Henvendelse"), NOW() > CustomOpportunity__c.TAG_DueDateTime__c)
    ), 
    1, 0
)
